// The token is stored in the Get Intellicar Token node output
const token = $node["Get Intellicar Token"].json.data.token;

// List Vehicles returns an array; wrap it if needed
const raw = $json;
const vehicles = Array.isArray(raw) ? raw
  : Array.isArray(raw.data) ? raw.data
  : [];

if (vehicles.length === 0) {
  throw new Error('No vehicles returned from Intellicar API');
}

// Return one item per vehicle, each carrying the token
return vehicles.map(v => ({
  json: {
    vehicleno: v.vehicleno || v.vehicle_no || v.vehicleNo || '',
    token
  }
}));

const vehicleNo = $node["Vehicle Loop"].json.vehicleno;
const now = new Date().toISOString();
const sixtyMinsAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();

// ── GPS ──────────────────────────────────────────────────────────────
const gpsRaw = $node["Get GPS Status"].json;
const gpsData = gpsRaw?.data || gpsRaw || {};
const lat = Number(gpsData?.latitude || gpsData?.lat || 0);
const lon = Number(gpsData?.longitude || gpsData?.lng || 0);

let gpsPayload = [];
if (!isNaN(lat) && !isNaN(lon) && lat !== 0 && lon !== 0) {
  const speed = Number(gpsData?.speed || 0);
  gpsPayload = [{
    time: now,
    device_id: vehicleNo,
    latitude: lat,
    longitude: lon,
    altitude: Number(gpsData?.altitude || 0),
    speed,
    heading: Number(gpsData?.heading || 0),
    device_battery: Number(gpsData?.devbattery || gpsData?.device_battery || 0),
    vehicle_battery: Number(gpsData?.carbattery || gpsData?.vehicle_battery || 0),
    ignition_on: gpsData?.ignstatus === 1 || gpsData?.ignition === 1 || gpsData?.ignition_on === true,
    is_moving: speed > 0
  }];
}

// ── CAN ──────────────────────────────────────────────────────────────
const canRaw = $node["Get Latest CAN"].json;
const canData = canRaw?.data || canRaw || {};

const extractFloat = (keys, data) => {
  for (const k of keys) {
    if (data[k] != null) {
      return typeof data[k] === 'object' ? Number(data[k].value ?? 0) : Number(data[k]);
    }
  }
  return null;
};

const soc = extractFloat(['soc', 'SOC', 'battery_soc'], canData);
const soh = extractFloat(['soh', 'SOH', 'battery_soh'], canData);
const voltage = extractFloat(['voltage', 'batt_vol', 'battery_voltage'], canData) ?? 0;
const current = extractFloat(['current', 'batt_cur', 'battery_current'], canData) ?? 0;
const temp = extractFloat(['temperature', 'batt_temp', 'temp'], canData);
const chargeCycle = extractFloat(['charge_cycle', 'cycles'], canData);

let canPayload = [];
if (soc !== null || voltage !== 0) {
  canPayload = [{
    time: now,
    vehiclenos: vehicleNo,
    soc,
    soh,
    voltage,
    current,
    charge_cycle: chargeCycle,
    temperature: temp,
    power_watts: voltage * current,
    source: 'live'
  }];
}

// ── TRIPS ─────────────────────────────────────────────────────────────
const distRaw = $node["Get Distance Travelled"].json;
const distItems = Array.isArray(distRaw)
  ? distRaw
  : Array.isArray(distRaw?.data) ? distRaw.data
  : (distRaw ? [distRaw] : []);

const tripsPayload = [];
for (const d of distItems) {
  const distKm = Number(d?.distance_km || d?.distance || d?.totaldistance || 0);
  if (distKm > 0) {
    tripsPayload.push({
      device_id: vehicleNo,
      start_time: sixtyMinsAgo,
      end_time: now,
      start_odometer: Number(d?.start_odometer || d?.startodo || 0),
      end_odometer: Number(d?.end_odometer || d?.endodo || 0),
      distance_km: distKm
    });
  }
}

return [{ json: { vehicleNo, gpsPayload, canPayload, tripsPayload } }];
